// FILE: native/add.c
#include <stdint.h>

// Export symbol so Dart can find it. On Windows also need __declspec(dllexport).
__attribute__((visibility("default"))) __attribute__((used))
int32_t add(int32_t a, int32_t b) {
  return a + b;
}

// Build:
//   macOS:   clang -shared -o libmath.dylib add.c
//   Linux:   gcc -shared -fPIC -o libmath.so add.c
//   Android: use CMake in android/CMakeLists.txt (ndk build)
//   iOS:     compile into a static/xcframework and link in the Runner.

// FILE: lib/math_ffi.dart
import 'dart:ffi';
import 'dart:io' show Platform;
import 'package:ffi/ffi.dart';

// Dart typedef matching the C signature
typedef _AddC = Int32 Function(Int32 a, Int32 b);      // C-side types
typedef _AddDart = int Function(int a, int b);          // Dart-side types

class NativeMath {
  static final DynamicLibrary _lib = _open();
  static final _AddDart add = _lib
      .lookup<NativeFunction<_AddC>>('add')
      .asFunction<_AddDart>();

  static DynamicLibrary _open() {
    if (Platform.isMacOS) return DynamicLibrary.open('libmath.dylib');
    if (Platform.isLinux) return DynamicLibrary.open('libmath.so');
    if (Platform.isAndroid) return DynamicLibrary.open('libmath.so');
    if (Platform.isWindows) return DynamicLibrary.open('math.dll');
    if (Platform.isIOS) return DynamicLibrary.process();   // statically linked
    throw UnsupportedError('Unsupported platform');
  }
}

// Usage — it feels like calling a regular Dart function
void main() {
  print(NativeMath.add(2, 3));   // 5
  print(NativeMath.add(100, 42)); // 142
}

// Notice: no async, no serialization, no channel. Just a function call.
// A million adds in ~milliseconds — impossible with platform channels.

import 'dart:ffi';
import 'package:ffi/ffi.dart';   // provides Utf8 + calloc

// C signature:  const char* hello(const char* name);
typedef _HelloC = Pointer<Utf8> Function(Pointer<Utf8> name);
typedef _HelloDart = Pointer<Utf8> Function(Pointer<Utf8> name);

final _hello = DynamicLibrary.open('libhello.so')
    .lookup<NativeFunction<_HelloC>>('hello')
    .asFunction<_HelloDart>();

String hello(String name) {
  // Allocate a UTF-8 buffer for the input
  final namePtr = name.toNativeUtf8();
  try {
    final resultPtr = _hello(namePtr);
    return resultPtr.toDartString();
    // If the C function malloc'd the string, YOU must call `calloc.free(resultPtr)`
    // matching whatever allocator it used. Otherwise → leak.
  } finally {
    calloc.free(namePtr);   // always free the input we allocated
  }
}

// Same pattern for byte buffers: allocate<Uint8>(size), copy in, pass pointer,
// C fills / reads, you free.
